          </div>
        </SectionBlock>
        <SerialInput serials={serials} setSerials={setSerials} page={7} stage="Final Visual" />
      </PageSection>

      {/* ─── SUBMIT BAR ─── */}
      <div style={{
        position: 'sticky', bottom: 0, zIndex: 100,
        background: 'linear-gradient(180deg, rgba(248,250,252,0) 0%, rgba(248,250,252,1) 20%)',
        padding: '24px 0 8px',
      }}>
        <div style={{
          display: 'flex', gap: 12, justifyContent: 'center', alignItems: 'center',
          padding: '16px 24px', background: C.card, borderRadius: 14,
          border: `1.5px solid ${C.border}`, boxShadow: C.shadowLg,
        }}>
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={{ fontSize: 13, color: C.textMuted, fontWeight: 600 }}>
              {totalFilled.filled} / {totalFilled.total} fields filled
            </span>
            <div style={{ width: 100, height: 6, background: '#e2e8f0', borderRadius: 3, overflow: 'hidden' }}>
              <div style={{
                width: `${totalFilled.total > 0 ? (totalFilled.filled / totalFilled.total * 100) : 0}%`,
                height: '100%', background: `linear-gradient(90deg, ${C.success} 0%, #34d399 100%)`, borderRadius: 3, transition: 'width 0.5s',
              }} />
            </div>
            {serials.length > 0 && (
              <span style={{ fontSize: 11, color: C.primaryLight, fontWeight: 600, background: C.primaryBg, padding: '2px 8px', borderRadius: 6 }}>
                {serials.length} serials
              </span>
            )}
          </div>
          <button onClick={handleSave} disabled={saving}
            style={{
              padding: '12px 36px', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 700,
              cursor: saving ? 'default' : 'pointer', color: '#fff', letterSpacing: '0.02em',
              background: saving ? '#94a3b8' : 'linear-gradient(135deg, #059669 0%, #10b981 100%)',
              boxShadow: saving ? 'none' : '0 4px 12px rgba(16,185,129,0.35)',
              transition: 'all 0.3s', display: 'flex', alignItems: 'center', gap: 8,
            }}>
            {saving ? <><Spinner /> Saving...</> : <><span style={{ fontSize: 16 }}>💾</span> Save Checksheet</>}
          </button>
          <button onClick={resetForm}
            style={{
              padding: '12px 24px', background: '#f1f5f9', color: C.textMuted, border: `1.5px solid ${C.border}`,
              borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: 'pointer', transition: 'all 0.2s',
            }}>
            🔄 Reset
          </button>
        </div>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════
//  HELPER COMPONENTS
// ══════════════════════════════════════════════

function ViewField({ label, value, unit }) {
  const hasVal = value !== null && value !== undefined && value !== '';
  return (
    <div style={{ marginBottom: 6 }}>
      <span style={{ fontSize: 10, color: C.textMuted, fontWeight: 600, letterSpacing: '0.03em', textTransform: 'uppercase' }}>{label}</span>
      <div style={{
        fontSize: 14, fontWeight: 600, color: hasVal ? C.text : '#cbd5e1',
        padding: '4px 0', borderBottom: `1px dashed ${hasVal ? C.borderLight : '#f1f5f9'}`,
      }}>
        {hasVal ? <>{value}{unit ? <span style={{ color: C.textLight, fontSize: 11, marginLeft: 3 }}>{unit}</span> : ''}</> : '—'}
      </div>
    </div>
  );
}

function ViewSection({ title, color, children }) {
  return (
    <div style={{ marginBottom: 20 }}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12,
        padding: '8px 0', borderBottom: `2px solid ${color}22`,
      }}>
        <div style={{ width: 4, height: 20, borderRadius: 2, background: color }} />
        <h4 style={{ margin: 0, fontSize: 14, fontWeight: 700, color: C.text }}>{title}</h4>
      </div>
      {children}
    </div>
  );
}

function FraudBadge({ verdict, style = {} }) {
  const colors = { GENUINE: C.success, NEEDS_REVIEW: C.warning, SUSPICIOUS: '#f97316', LIKELY_DUMMY: C.danger };
  const col = colors[verdict] || '#64748b';
  return (
    <span style={{
      background: col + '18', color: col, padding: '3px 8px', borderRadius: 6,
      fontSize: 10, fontWeight: 700, border: `1.5px solid ${col}33`, letterSpacing: '0.03em', ...style,
    }}>{verdict}</span>
  );
}

function StatCard({ icon, label, value, color }) {
  return (
    <div style={{
      background: C.card, borderRadius: 12, border: `1.5px solid ${C.border}`,
      padding: '16px 18px', display: 'flex', alignItems: 'center', gap: 14,
      boxShadow: C.shadow, transition: 'all 0.2s',
    }}>
      <div style={{
        width: 44, height: 44, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: `${color}10`, fontSize: 22,
      }}>{icon}</div>
      <div>
        <div style={{ fontSize: 22, fontWeight: 800, color: color || C.text, lineHeight: 1 }}>{value}</div>
        <div style={{ fontSize: 11, color: C.textMuted, fontWeight: 500, marginTop: 2 }}>{label}</div>
      </div>
    </div>
  );
}

function Btn({ icon, label, color, onClick, disabled }) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      padding: '9px 18px', background: color, color: '#fff', border: 'none', borderRadius: 8,
      fontSize: 12, fontWeight: 700, cursor: disabled ? 'default' : 'pointer',
      boxShadow: `0 2px 8px ${color}33`, display: 'flex', alignItems: 'center', gap: 6,
      opacity: disabled ? 0.6 : 1, transition: 'all 0.2s', letterSpacing: '0.02em',
    }}>{icon} {label}</button>
  );
}

function IconBtn({ icon, color, onClick, title }) {
  return (
    <button onClick={onClick} title={title} style={{
      padding: '5px 10px', background: `${color}12`, color: color, border: `1.5px solid ${color}33`,
      borderRadius: 8, fontSize: 13, cursor: 'pointer', fontWeight: 600, transition: 'all 0.2s',
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
    }}>{icon}</button>
  );
}

function Spinner() {
  return (
    <span style={{
      display: 'inline-block', width: 14, height: 14, border: '2px solid rgba(255,255,255,0.3)',
      borderTopColor: '#fff', borderRadius: '50%', animation: 'spin 0.6s linear infinite',
    }}>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </span>
  );
}

const tdStyle = { padding: '10px 14px', borderBottom: `1px solid ${C.borderLight}`, fontSize: 13 };

export default IPQCFormPage;
